'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/components/auth-provider';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Plus, FileText } from 'lucide-react';
import { LogFormModal } from '@/components/log-form-modal';
import { LogItem } from '@/components/log-item';

interface Post {
  id: string;
  category: string;
  title: string;
  content: string | null;
  thumbnail_url: string | null;
  created_at: string;
}

interface PostImage {
  id: string;
  post_id: string;
  image_url: string;
  sort_order: number;
}

export interface LogPost extends Post {
  images: PostImage[];
}

export function LogList() {
  const { hasPermission } = useAuth();

  const [posts, setPosts] = useState<LogPost[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [showFormModal, setShowFormModal] = useState(false);

  const fetchPosts = useCallback(async () => {
    try {
      const res = await fetch('/api/posts?category=log');
      if (res.ok) {
        const data = await res.json();
        setPosts(data);
      }
    } catch (error) {
      console.error('Failed to fetch posts:', error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchPosts();
  }, [fetchPosts]);

  const handleAddClick = () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    setShowFormModal(true);
  };

  const handleFormSuccess = () => {
    fetchPosts();
    setShowFormModal(false);
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        {[...Array(3)].map((_, i) => (
          <Card key={i} className="p-6">
            <div className="flex gap-6">
              <div className="w-1/2 aspect-video bg-muted animate-pulse" />
              <div className="w-1/2 space-y-4">
                <div className="h-6 bg-muted animate-pulse w-3/4" />
                <div className="h-4 bg-muted animate-pulse w-full" />
                <div className="h-4 bg-muted animate-pulse w-2/3" />
              </div>
            </div>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <>
      {posts.length === 0 ? (
        <Card className="p-12 text-center">
          <div className="flex flex-col items-center gap-4 text-muted-foreground">
            <FileText className="h-12 w-12" />
            <p>등록된 글이 없습니다.</p>
          </div>
        </Card>
      ) : (
        <div className="space-y-6">
          {posts.map((post) => (
            <LogItem key={post.id} post={post} onDelete={fetchPosts} />
          ))}
        </div>
      )}

      

      <LogFormModal
        open={showFormModal}
        onOpenChange={setShowFormModal}
        onSuccess={handleFormSuccess}
      />
    </>
  );
}
