'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/components/auth-provider';
import Image from 'next/image';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Trash2, Send, ChevronLeft, ChevronRight, ImageIcon } from 'lucide-react';
import { toast } from 'sonner';
import type { LogPost } from '@/components/log-list';

interface Comment {
  id: string;
  author: string;
  content: string;
  created_at: string;
}

interface LogItemProps {
  post: LogPost;
  onDelete: () => void;
}

export function LogItem({ post, onDelete }: LogItemProps) {
  const { hasPermission } = useAuth();
  
  const [currentImageIndex, setCurrentImageIndex] = useState(0);
  const [comments, setComments] = useState<Comment[]>([]);
  const [newComment, setNewComment] = useState('');
  const [commentAuthor, setCommentAuthor] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const fetchComments = useCallback(async () => {
    if (!post?.id) return;
    try {
      const res = await fetch(`/api/comments?postId=${post.id}`);
      if (res.ok) {
        const data = await res.json();
        if (Array.isArray(data)) {
            setComments(data);
        }
      }
    } catch (error) {
      console.error('Failed to fetch comments:', error);
    }
  }, [post?.id]);

  useEffect(() => {
    fetchComments();
  }, [fetchComments]);

  if (!post) return null;
  const images = post.images || [];

  const handlePrevImage = () => {
    setCurrentImageIndex((prev) =>
      prev === 0 ? images.length - 1 : prev - 1
    );
  };

  const handleNextImage = () => {
    setCurrentImageIndex((prev) =>
      prev === images.length - 1 ? 0 : prev + 1
    );
  };

  const handleDeleteClick = async () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    if (!confirm('정말로 삭제하시겠습니까?')) return;

    try {
      const res = await fetch(`/api/posts/${post.id}`, {
        method: 'DELETE',
      });

      if (res.ok) {
        toast.success('글이 삭제되었습니다.');
        onDelete();
      } else {
        toast.error('삭제에 실패했습니다.');
      }
    } catch {
      toast.error('삭제 중 오류가 발생했습니다.');
    }
  };

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!commentAuthor.trim() || !newComment.trim()) {
      toast.error('이름과 댓글을 모두 입력해주세요.');
      return;
    }

    setIsSubmitting(true);
    try {
      const res = await fetch('/api/comments', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          postId: post.id,
          author: commentAuthor,
          content: newComment,
        }),
      });

      if (res.ok) {
        setNewComment('');
        fetchComments();
        toast.success('댓글이 등록되었습니다.');
      } else {
        toast.error('댓글 등록에 실패했습니다.');
      }
    } catch {
      toast.error('댓글 등록 중 오류가 발생했습니다.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const formatDate = (dateString: string) => {
    if (!dateString) return '';
    try {
      return new Date(dateString).toLocaleDateString('ko-KR', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch {
      return '';
    }
  };

  return (
    <>
      <Card className="overflow-hidden shadow-none border-0 bg-card/75 backdrop-blur-sm">
        <CardHeader className="flex flex-row items-center justify-between pb-2">
          <div>
            <CardTitle className="text-xl">{post.title}</CardTitle>
            <p className="text-sm text-muted-foreground mt-1">
              {formatDate(post.created_at)}
            </p>
          </div>
          <Button
            variant="ghost"
            size="icon"
            onClick={handleDeleteClick}
            className="text-black hover:text-black hover:bg-black/10 transition-colors"
            title="삭제"
          >
            <Trash2 className="h-4 w-4" />
          </Button>
        </CardHeader>
        <CardContent>
          <div className="flex flex-col lg:flex-row gap-6">
            {/* Left: Images */}
            <div className="lg:w-1/2">
              {images?.length > 0 ? (
                <div className="relative">
                  <div className="aspect-video relative bg-muted">
                    {images[currentImageIndex]?.image_url ? (
                      <Image
                        src={images[currentImageIndex].image_url}
                        alt={`${post.title} - ${currentImageIndex + 1}`}
                        fill
                        className="object-contain"
                      />
                    ) : (
                      <div className="w-full h-full flex items-center justify-center">
                        <ImageIcon className="h-12 w-12 text-muted-foreground" />
                      </div>
                    )}
                  </div>
                  {images.length > 1 && (
                    <>
                      <Button
                        variant="secondary"
                        size="icon"
                        className="absolute left-2 top-1/2 -translate-y-1/2"
                        onClick={handlePrevImage}
                      >
                        <ChevronLeft className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="secondary"
                        size="icon"
                        className="absolute right-2 top-1/2 -translate-y-1/2"
                        onClick={handleNextImage}
                      >
                        <ChevronRight className="h-4 w-4" />
                      </Button>
                      <div className="absolute bottom-2 left-1/2 -translate-x-1/2 bg-foreground/80 text-background px-2 py-1 text-sm">
                        {currentImageIndex + 1} / {images.length}
                      </div>
                    </>
                  )}
                </div>
              ) : (
                <div className="aspect-video bg-muted flex items-center justify-center">
                  <ImageIcon className="h-12 w-12 text-muted-foreground" />
                </div>
              )}
              {post.content && (
                <div className="mt-4 p-4 bg-muted">
                  <p className="whitespace-pre-wrap text-foreground">{post.content}</p>
                </div>
              )}
            </div>

            {/* Right: Comments */}
            <div className="lg:w-1/2 flex flex-col">
              <h3 className="text-lg font-medium mb-4">댓글 ({comments.length})</h3>
              
              <ScrollArea className="flex-1 h-[300px] mb-4">
                {!comments || comments.length === 0 ? (
                  <p className="text-muted-foreground text-center py-8">
                    아직 댓글이 없습니다.
                  </p>
                ) : (
                  <div className="space-y-4">
                    {comments.map((comment) => (
                      <div key={comment.id} className="pb-4">
                        <div className="flex justify-between items-start mb-2">
                          <span className="font-medium text-foreground">{comment.author}</span>
                          <span className="text-xs text-muted-foreground">
                            {formatDate(comment.created_at)}
                          </span>
                        </div>
                        <p className="text-foreground">{comment.content}</p>
                      </div>
                    ))}
                  </div>
                )}
              </ScrollArea>

              <form onSubmit={handleSubmitComment} className="flex flex-col p-3 pb-2 pt-0">
                <Input
                  className="border-0 bg-transparent focus-visible:ring-0 focus-visible:ring-offset-0 px-2 h-8"
                  placeholder="이름"
                  value={commentAuthor}
                  onChange={(e) => setCommentAuthor(e.target.value)}
                />
                <div className="flex gap-2 items-end border-t border-border/50 pt-2 mt-2">
                  <Textarea
                    className="border-0 bg-transparent focus-visible:ring-0 focus-visible:ring-offset-0 resize-none px-2 min-h-[40px] max-h-[80px]"
                    placeholder="댓글을 입력하세요..."
                    value={newComment}
                    onChange={(e) => setNewComment(e.target.value)}
                    rows={2}
                  />
                  <Button type="submit" disabled={isSubmitting} variant="ghost" size="icon" className="mb-1 text-muted-foreground hover:text-foreground hover:bg-transparent bg-transparent">
                    <Send className="h-5 w-5" />
                  </Button>
                </div>
              </form>
            </div>
          </div>
        </CardContent>
      </Card>

      
    </>
  );
}
